head.script:
// 화면 - Id: sl_101_01_04b.jsp,v 1.15 2016/07/07 07:43:45 guyorimi Exp 
// 설명 - 입출고내역을 조회한다.

scwin.nowDt = $c.date.getServerDateTime();
scwin.todayDt = $c.date.getDateAddMonthDirection(scwin.nowDt, 0 , "F");
scwin.hd_vsslCd = "";

scwin.onpageload = function () {
    scwin.f_HeaderCreate();		// 조건문 Header Create
};

scwin.onUdcCompleted = function () {
    $c.gus.cfDisableObjects([ed_clntNo, ed_clntNm, ed_commCd, ed_commNm]);
    ed_inoutStDt.setValue(scwin.todayDt); 
    ed_inoutEndDt.setValue(scwin.nowDt); 
};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_HeaderCreate = function () {
	ds_search.removeAll()
	ds_search.insertRow();
    ds_search.setRowPosition(0);
};

// 조회
scwin.f_Retrieve = async function () {
    let searchChk = await $c.gus.cfValidate([tbl_condition]);
    if (!searchChk) {	 
        return;
    } 

    let e = await $c.sbm.execute(sbm_stockAmt);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_stockAmt_submitdone(e);
    }
};

// 휴지통 처리
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_condition, []);
    ed_arvStDt.focus();
};

// 엑셀 출력
scwin.f_Excel = function() {	  
    var count = ds_stockInOutDetail.getRowCount();	  
    if (!(count > 0)) return;

    var infoArr = [
        {
            rowIndex: 0,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "입출고내역조회",
            textAlign: "center",
            fontName: "돋움체",
            fontSize: 12,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
        {
            rowIndex: 2,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "입출고일자" + " [" + $c.gus.cfGetFormatStr(ed_inoutStDt.getValue(), "####/##/##") + " ~ " + $c.gus.cfGetFormatStr(ed_inoutEndDt.getValue(), "####/##/##") + "]",
            textAlign: "left",
            fontName: "굴림체",
            fontSize: 10,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
        {
            rowIndex: 3,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "화주" + " [" + ed_clntNm.getValue() + "]",
            textAlign: "left",
            fontName: "굴림체",
            fontSize: 10,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
        {
            rowIndex: 4,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "품목" + " [" + ed_commNm.getValue() + "]",
            textAlign: "left",
            fontName: "굴림체",
            fontSize: 10,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
        {
            rowIndex: 5,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "입항일자" + " [" + $c.gus.cfGetFormatStr(ed_arvStDt.getValue(), "####/##/##") + " ~ " + $c.gus.cfGetFormatStr(ed_arvEndDt.getValue(), "####/##/##") + "]",
            textAlign: "left",
            fontName: "굴림체",
            fontSize: 10,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
        {
            rowIndex: 6,
            colIndex: 0,
            rowSpan: 1,
            colSpan: 12,
            text: "본선" + " [" + ed_vsslNm.getValue() + "]",
            textAlign: "left",
            fontName: "굴림체",
            fontSize: 10,
            bgColor : "#ffffff",
            drawBorder: false
        }, 
    ];

    var options = {
        fileName: "입출고내역조회" + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        , sheetName: "입출고내역조회"
        , type : 4 + 8 + 16
        , startRowIndex : 7
        , removeColumns : "11"
    };

    $c.data.downloadGridViewExcel(gr_stockInOutDetail, options, infoArr);
};

// 본선관리번호검색 팝업창 띄우기
scwin.f_openPopUp = async function () {
	var args = new Array();
	args[0] = ed_cvsslMgntNo.getValue(); // 본선관리번호
	args[1] = "";                        // 수출입구분코드

    var opts = {
        id : "smpPop"	
        , popupName : "본선관리번호검색팝업"
        , modal : true
        , type : "browserPopup"
        , width : 1230
        , height : 550 
        , title : "본선관리번호검색팝업"
    };

    var rtnList = await $c.win.openPopup("/ui/ds/sl/sl_101_01_01p.xml", opts, args);

    if (rtnList != null) {
        ed_cvsslMgntNo.setValue(rtnList[0]);  
        scwin.hd_vsslCd = rtnList[1];  
        ed_vsslNm.setValue(rtnList[2]); 
    }
};

// Pop up 
