scwin.gr_stockInOutDetail_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "stockWt") {
        val = "";
    } 

    return val;
};

